urlset:

  {{ url_for('frontend.landing_page', _external=True) }}


  {{ url_for('wodreport.report_page', _external=True) }}

{%- for category in categories %}

  {{ url_for('wodreport.view_category', category_id=category.id, _external=True) }}
  {%- if category.updated_at %}
  {{ category.updated_at.strftime('%Y-%m-%d') }}
  {%- endif %}

{%- endfor %}
{%- for report in reports %}

  {{ url_for('wodreport.view_report', report_id=report.id, _external=True) }}
  {%- if report.updated_at %}
  {{ report.updated_at.strftime('%Y-%m-%d') }}
  {%- endif %}

{%- endfor %}
